const apiKey = 'YOUR_API_KEY';
const movieId = '550';

fetch(`https://webservice.fanart.tv/v3.2/movies/${movieId}?api_key=${apiKey}`)
  .then(response => response.json())
  .then(data => console.log(data))
  .catch(error => console.error('Error:', error));

const apiKey = 'YOUR_API_KEY';
const movieId = '550';

fetch(`https://webservice.fanart.tv/v3.2/movies/${movieId}`, {
  headers: {
    'api-key': apiKey
  }
})
  .then(response => response.json())
  .then(data => console.log(data))
  .catch(error => console.error('Error:', error));

const axios = require('axios');

const apiKey = 'YOUR_API_KEY';
const movieId = '550';

axios.get(`https://webservice.fanart.tv/v3.2/movies/${movieId}`, {
  params: { api_key: apiKey }
})
.then(response => console.log(response.data))
.catch(error => console.error('Error:', error));

package main

import (
    "encoding/json"
    "fmt"
    "io"
    "net/http"
)

func main() {
    apiKey := "YOUR_API_KEY"
    movieID := "550"

    url := fmt.Sprintf("https://webservice.fanart.tv/v3.2/movies/%s?api_key=%s", movieID, apiKey)

    resp, err := http.Get(url)
    if err != nil {
        panic(err)
    }
    defer resp.Body.Close()

    body, _ := io.ReadAll(resp.Body)

    var data map[string]interface{}
    json.Unmarshal(body, &data)

    fmt.Println(data)
}

